SELECT COUNT(DISTINCT LPB.PK) AS TOTAL FROM LATTES_PRODBIB LPB JOIN LATTES_P_PRODBIB PP ON PP.FK_PRODBIB = LPB.PK JOIN SERVIDOR S ON S.PK_SIAPE = PP.FK_SIAPE WHERE LOWER(COALESCE(LPB.TIPO,'')) = 'trabalho em evento' AND LOWER(COALESCE(LPB.NATUREZA,'')) = 'completo' AND LOWER(COALESCE(LPB.ANO,'')) = '2023' AND LOWER(COALESCE(S.SIGLA_CAMPUS,'')) = 'val' AND LOWER(COALESCE(S.GENERO,'')) = 'feminino'